```csharp
using System.Collections;
using UnityEngine;

public class LightColorAndRotate : MonoBehaviour
{
    public Light targetLight;                  // Reference to the Light component
    public Color startColor;                   // The initial color of the light
    public Color endColor;                     // The final color to lerp to
    public float lerpDuration = 2f;            // Duration over which the color lerping occurs

    private void Start()
    {
        // Optionally set the initial properties on start
        if (targetLight != null)
        {
            targetLight.color = startColor;
            StartColorAndRotationLerp();
        }
    }

    // Public method to start the color lerp and rotation - call this to trigger the effects
    public void StartColorAndRotationLerp()
    {
        StartCoroutine(LerpLightColorAndRotation(startColor, endColor, lerpDuration));
    }

    private IEnumerator LerpLightColorAndRotation(Color fromColor, Color toColor, float duration)
    {
        float timeElapsed = 0f;
        Quaternion initialRotation = targetLight.transform.localRotation;
        Quaternion targetRotation = Quaternion.Euler(initialRotation.eulerAngles.x,
                                                     initialRotation.eulerAngles.y + 360f,
                                                     initialRotation.eulerAngles.z);

        while (timeElapsed < duration)
        {
            float lerpRatio = timeElapsed / duration;
            // Lerp color
            targetLight.color = Color.Lerp(fromColor, toColor, lerpRatio);

            // Perform rotation
            targetLight.transform.localRotation = Quaternion.Lerp(initialRotation, targetRotation, lerpRatio);

            timeElapsed += Time.deltaTime;
            yield return null; // Wait for the next frame and continue
        }

        // Ensure the final color and rotation are set after the loop is done
        targetLight.color = toColor;
        targetLight.transform.localRotation = targetRotation;
    }
}
